// src/components/TratamentoPaciente.js
import React, { useState } from "react";

/**
 * Estrutura de exemplo. Depois integre com a API real do backend.
 */
const MOCK_TRATAMENTOS = [
  {
    id: 1,
    descricao: "Obturação dente 26",
    data_inicio: "2024-07-24",
    status: "Em andamento"
  },
  {
    id: 2,
    descricao: "Limpeza profilática",
    data_inicio: "2024-06-02",
    status: "Concluído"
  }
];

export default function TratamentoPaciente({ pacienteId }) {
  // Troque MOCK_TRATAMENTOS pela chamada à API depois
  const [tratamentos, setTratamentos] = useState(MOCK_TRATAMENTOS);

  function handleNovoTratamento() {
    // Aqui pode abrir um modal ou formulário inline para adicionar novo tratamento
    alert("Funcionalidade de adicionar novo tratamento (implementar)");
  }

  return (
    <div>
      <h2 className="text-xl font-bold mb-4">Tratamentos & Odontograma</h2>
      <p className="mb-6 text-gray-600">
        Paciente ID: <span className="font-mono">{pacienteId}</span>
      </p>

      {/* Botão para adicionar novo tratamento */}
      <button
        onClick={handleNovoTratamento}
        className="bg-[#1A1C2C] text-white px-4 py-2 rounded-full mb-4 hover:bg-[#3B4854] transition"
      >
        + Novo Tratamento
      </button>

      {/* Lista de tratamentos (mock) */}
      <div className="mb-8">
        <h3 className="font-semibold text-lg mb-2">Histórico de Tratamentos</h3>
        {tratamentos.length === 0 ? (
          <p className="text-gray-500">Nenhum tratamento registrado.</p>
        ) : (
          <ul className="divide-y divide-gray-200">
            {tratamentos.map(trat => (
              <li key={trat.id} className="py-2 flex justify-between items-center">
                <span>
                  <strong>{trat.descricao}</strong> <br />
                  <span className="text-xs text-gray-500">
                    Início: {trat.data_inicio} | Status: {trat.status}
                  </span>
                </span>
                {/* Coloque botões de editar/remover aqui depois */}
              </li>
            ))}
          </ul>
        )}
      </div>

      {/* Placeholder Odontograma */}
      <div className="mt-8 border rounded-lg p-6 bg-gray-50">
        <h3 className="font-semibold text-lg mb-3">Odontograma</h3>
        <div className="text-gray-400 italic text-center py-8">
          [ Odontograma visual aqui em breve... ]
        </div>
        {/* 
          Depois, substitua esse bloco por um componente de odontograma
          (SVG interativo ou biblioteca)
        */}
      </div>
    </div>
  );
}
